+func TestRenamePrefixInDB(t *testing.T) {
+	tmpDir := t.TempDir()
+	dbPath := filepath.Join(tmpDir, "test.db")
+
+	testStore, err := sqlite.New(dbPath)
+	if err != nil {
+		t.Fatalf("Failed to create test database: %v", err)
+	}
+	t.Cleanup(func() {
+		testStore.Close()
+		os.Remove(dbPath)
+	})
+
+	ctx := context.Background()
+	store = testStore
